// // This is a 1-to-2 demultiplexer that outputs one of the two 8-bit inputs based on the select signal.
module mux_2to1_8bit
(
    input sel,
    input [7:0] in0,
    input [7:0] in1,
    output reg [7:0] out
);

always @(*) begin
    if (sel) begin
        out = in1;
    end else begin
        out = in0;
    end
end

endmodule
